UPDATE articles SET content = '[{"id":"m1","type":"paragraph","text":"В одну из локаций **Harbor (Гавань)** прибывает грузовое судно. Ваша цель — захватить контейнер с элитным лутом, пока корабль не покинул остров."},{"id":"m2","type":"warning","icon":"Тяжёлая техника!","text":"Зона разгрузки охраняется **Танком Бредли**. Уничтожьте его первым — иначе он не даст вам подойти к крану."},{"id":"m3","type":"heading2","text":"🚢 Порядок действий"},{"id":"m4","type":"step","stepNum":1,"text":"**Уничтожение Танка:** Чтобы подойти к крану — уничтожьте Танк, который охраняет корабль."},{"id":"m5","type":"step","stepNum":2,"text":"**Активация кнопки на кране:** Проберитесь в **кабину крана** и нажмите кнопку. Это запустит процесс разгрузки контейнера с корабля."},{"id":"m6","type":"step","stepNum":3,"text":"**Активация ящика в контейнере:** Как только контейнер опустится — двери разблокируются. Внутри будет **запертый ящик**, на который нужно нажать."},{"id":"m7","type":"warning","icon":"Прибытие подкрепления!","text":"Сразу после активации запертого ящика в зону ивента **прилетит патрульный вертолёт**. Будьте готовы к воздушному бою!"},{"id":"m8","type":"heading2","text":"📦 Список добычи"},{"id":"m9","type":"list","ordered":false,"items":["📦 1 Запертый ящик (в контейнере)","🛠️ 6 Различных ящиков (в контейнере)","📦 3 Запертых ящика (на корабле)","🛠️ 27 Различных ящиков (на корабле)"]},{"id":"m10","type":"warning","icon":"⏱️ Следите за таймером!","text":"Когда время выйдет — корабль уплывёт в море со всем оставшимся добром."},{"id":"m11","type":"tip","icon":"Не забудьте!","text":"После победы над техникой **залутайте ящики** из обломков **Танка** и **Вертолёта**. Затем используйте **Бур (Jackhammer)** или **Кирку (Pickaxe)** чтобы разобрать остовы на ценный металл!"}]' WHERE id = 18;

UPDATE articles SET content = '[{"id":"n1","type":"paragraph","text":"На острове появляется временная локация — **военный блокпост**. Ваша задача: защитить раненого генерала от орд зомби до прибытия спасательного вертолёта."},{"id":"n2","type":"heading2","text":"🧟 Как это работает"},{"id":"n3","type":"step","stepNum":1,"text":"**Начало:** Следите за чатом. Когда появится уведомление — найдите блокпост на карте и отправляйтесь туда."},{"id":"n4","type":"step","stepNum":2,"text":"**Активация:** В центре базы найдите **ноутбук** и вызовите помощь. Это запустит таймер и волны врагов."},{"id":"n5","type":"step","stepNum":3,"text":"**Подготовка:** Через ноутбук можно ставить **турели** и покупать к ним патроны. В дверные проёмы ставьте **баррикады** — чем дороже, тем крепче."},{"id":"n6","type":"step","stepNum":4,"text":"**Оборона:** Зомби атакуют волнами. Главная цель — **не дать им убить генерала**. Возьмите **кирку (Hammer)** чтобы чинить пробитые баррикады."},{"id":"n7","type":"step","stepNum":5,"text":"**Награда:** После каждой отбитой волны открывается комната с **лутом**. Чем больше волн переживёте — тем ценнее награда."},{"id":"n8","type":"warning","icon":"Условие провала","text":"Если генерал умрёт — ивент провален. Охраняйте его в первую очередь!"},{"id":"n9","type":"tip","icon":"Финал","text":"Если генерал выживет до конца — его заберёт вертолёт и вы получите финальную награду."}]' WHERE id = 19;
